import { redirect } from 'next/navigation';
import { revalidateTag } from 'next/cache';
import { getCachedProducts, type Product } from '@/lib/products';

/* ------------------------------------------------------------------ */

/* ── Inline Server Action ──────────────────────────────────────────── */

/**
 * Sync the product catalog from upstream ERP/PIM data.
 *
 * This action:
 *  1. Invalidates the "products" cache tag so the **next** read of any
 *     cached catalog view re-fetches from the database.
 *  2. Redirects back to the page so the caller sees a confirmation banner.
 *
 * Because we return control to the browser immediately, the admin can
 * keep working while the cache entry is rebuilt on the next access.
 * This is a deliberate choice for a read-heavy admin — the product list
 * may be briefly stale, but the admin is never blocked.
 */
async function syncCatalog() {
  'use server';

  try {
    revalidateTag('products');
    console.log('[catalog] Cache tag "products" invalidated');
  } catch (err) {
    console.error('[catalog] Failed to revalidate products cache', err);
    redirect('/admin/catalog?sync=failed');
  }

  redirect('/admin/catalog?synced=1');
}

/* ── Helpers ────────────────────────────────────────────────────────── */

function formatCurrency(amount: number) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount);
}

/* ── Page ───────────────────────────────────────────────────────────── */

export default async function AdminCatalogPage(props: {
  searchParams?: Promise<{ synced?: string }>;
}) {
  const sp = props.searchParams ? await props.searchParams : {};
  const syncStatus: 'success' | 'failed' | null =
    sp.synced === '1' ? 'success' : sp.synced === 'failed' ? 'failed' : null;

  /* ── Data ── */
  let products: Product[];
  let fetchError: string | null = null;

  try {
    products = await getCachedProducts();
  } catch (err) {
    products = [];
    fetchError =
      err instanceof Error ? err.message : 'Failed to load product catalog.';
  }

  /* ── Render ── */
  return (
    <main
      style={{
        maxWidth: 960,
        margin: '0 auto',
        padding: '2rem 1rem',
        fontFamily:
          '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
      }}
    >
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '1.5rem',
        }}
      >
        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 600 }}>
          Product Catalog
        </h1>

        {/* Sync trigger — plain HTML form, no client JS needed */}
        <form action={syncCatalog}>
          <button
            type="submit"
            style={{
              padding: '0.5rem 1.25rem',
              fontSize: '0.875rem',
              fontWeight: 500,
              color: '#fff',
              backgroundColor: '#2563eb',
              border: 'none',
              borderRadius: 6,
              cursor: 'pointer',
            }}
          >
            Sync Latest Catalog
          </button>
        </form>
      </div>

      {/* ── Sync status banner ── */}
      {syncStatus === 'success' && (
        <Banner variant="success">
          Sync initiated — the catalog will be up to date shortly.
        </Banner>
      )}
      {syncStatus === 'failed' && (
        <Banner variant="error">
          Sync failed. Please try again or contact support.
        </Banner>
      )}

      {/* ── Error state ── */}
      {fetchError && (
        <Banner variant="error">{fetchError}</Banner>
      )}

      {/* ── Empty state ── */}
      {!fetchError && products.length === 0 && (
        <EmptyState />
      )}

      {/* ── Product table ── */}
      {!fetchError && products.length > 0 && (
        <div
          style={{
            border: '1px solid #e5e7eb',
            borderRadius: 8,
            overflow: 'hidden',
          }}
        >
          <table
            style={{
              width: '100%',
              borderCollapse: 'collapse',
              fontSize: '0.875rem',
            }}
          >
            <thead>
              <tr style={{ backgroundColor: '#f9fafb', textAlign: 'left' }}>
                <Th>ID</Th>
                <Th>Name</Th>
                <Th style={{ textAlign: 'right' }}>Price</Th>
              </tr>
            </thead>
            <tbody>
              {products.map((product) => (
                <tr
                  key={product.id}
                  style={{ borderTop: '1px solid #e5e7eb' }}
                >
                  <Td>{product.id}</Td>
                  <Td style={{ fontWeight: 500 }}>{product.name}</Td>
                  <Td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                    {formatCurrency(product.price)}
                  </Td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </main>
  );
}

/* ── Sub-components ─────────────────────────────────────────────────── */

function Th({
  children,
  style,
}: {
  children: React.ReactNode;
  style?: React.CSSProperties;
}) {
  return (
    <th
      scope="col"
      style={{
        padding: '0.625rem 1rem',
        fontWeight: 600,
        color: '#374151',
        ...style,
      }}
    >
      {children}
    </th>
  );
}

function Td({
  children,
  style,
}: {
  children: React.ReactNode;
  style?: React.CSSProperties;
}) {
  return (
    <td style={{ padding: '0.75rem 1rem', color: '#1f2937', ...style }}>
      {children}
    </td>
  );
}

function Banner({
  variant,
  children,
}: {
  variant: 'success' | 'error';
  children: React.ReactNode;
}) {
  const colors = {
    success: { bg: '#ecfdf5', fg: '#065f46', border: '#a7f3d0' },
    error: { bg: '#fef2f2', fg: '#991b1b', border: '#fecaca' },
  };
  const c = colors[variant];

  return (
    <div
      role="alert"
      style={{
        padding: '0.75rem 1rem',
        marginBottom: '1rem',
        fontSize: '0.875rem',
        backgroundColor: c.bg,
        color: c.fg,
        border: `1px solid ${c.border}`,
        borderRadius: 6,
      }}
    >
      {children}
    </div>
  );
}

function EmptyState() {
  return (
    <div
      style={{
        textAlign: 'center',
        padding: '3rem 1rem',
        color: '#6b7280',
        border: '1px dashed #d1d5db',
        borderRadius: 8,
      }}
    >
      <p style={{ margin: '0 0 0.5rem', fontSize: '1rem', fontWeight: 500 }}>
        No products found
      </p>
      <p style={{ margin: 0, fontSize: '0.875rem' }}>
        Click <strong>Sync Latest Catalog</strong> to pull product data from
        the upstream system.
      </p>
    </div>
  );
}

